<?php echo form_open(get_uri('grupo_donato/school/classes/enroll'),['id'=>'enrollment-form','class'=>'general-form']); ?><div class="modal-body"><input type="hidden" name="class_id" value="<?php echo $class_id; ?>"><div class="form-group"><label><?php echo app_lang('gd_school_student'); ?></label><?php echo form_dropdown('school_profile_id',array_column($profiles,'text','id'),'','class="form-control select2" required'); ?></div><div class="form-group"><label><?php echo app_lang('gd_product'); ?></label><?php echo form_dropdown('product_id',[''=>'-']+array_column($products,'text','id'),'','class="form-control select2"'); ?></div><div class="row"><div class="col-md-6"><label><?php echo app_lang('gd_school_start'); ?></label><input required type="date" class="form-control" name="starts_on" value="<?php echo date('Y-m-d'); ?>"></div><div class="col-md-6"><label><?php echo app_lang('gd_school_end'); ?></label><input type="date" class="form-control" name="ends_on"></div></div><div class="form-group mt-3"><label><?php echo app_lang('gd_school_due_day_info'); ?></label><input type="number" min="1" max="31" class="form-control" name="preferred_due_day"></div><div class="form-group"><label><?php echo app_lang('gd_status'); ?></label><?php echo form_dropdown('status',array_combine($statuses,array_map(fn($x)=>app_lang('gd_school_status_'.$x),$statuses)),'active','class="form-control"'); ?></div><div class="form-group"><label><?php echo app_lang('gd_notes'); ?></label><textarea class="form-control" name="notes"></textarea></div></div><div class="modal-footer"><button type="button" class="btn btn-default" data-bs-dismiss="modal"><?php echo app_lang('close'); ?></button><button type="submit" class="btn btn-primary"><?php echo app_lang('save'); ?></button></div><?php echo form_close(); ?><script>$(document).ready(function(){"use strict";$("#enrollment-form").appForm({onSuccess:function(){location.reload();}});$("#enrollment-form .select2").select2();});</script>
